import {type Plugin} from 'rolldown';
import {visualizer} from 'rollup-plugin-visualizer';

const {BUNDLE} = process.env;
const stats = BUNDLE === 'stats';

// jsonlint ships an autogenerated parser that uses the legacy `_token_stack:`
// label for an unrolled goto loop. Browsers don't optimize that pattern well,
// so the historic rollup build stripped the label. Match that behavior under
// rolldown by transforming just that file — the built-in replacePlugin has no
// include filter, so we use a small custom transform with a hook filter.
// See https://github.com/zaach/jison/issues/351
const stripJsonlintTokenStack: Plugin = {
    name: 'maplibre-strip-jsonlint-token-stack',
    transform: {
        filter: {
            id: /\/jsonlint-lines-primitives\/lib\/jsonlint\.js$/,
        },
        handler(code) {
            if (!code.includes('_token_stack:')) return null;
            return {
                code: code.replace(/_token_stack:/g, ''),
                map: null,
            };
        },
    },
};

// Common set of plugins/transformations shared across different rolldown
// builds (main maplibre bundle, benchmarks bundle).
//
// Rolldown has built-in support for TypeScript, JSON, CommonJS interop, node
// resolution, and minification, so the previous @rollup/plugin-* set is no
// longer needed. Browser-targeted node resolution is enabled at the config
// level via `platform: 'browser'`. The `_production` parameter is kept so
// downstream callers can still gate on it without us having to thread the
// signal through process.env at every layer.
export const plugins = (_production: boolean): Plugin[] => [
    stripJsonlintTokenStack,
    // Bundle-stats output uses the visualizer plugin (Rolldown ships with a
    // Rollup-compatible plugin API, so this still works). Visualizer is typed
    // for Rollup's Plugin shape; cast to Rolldown's superset.
    ...(stats ? (['treemap', 'sunburst', 'flamegraph', 'network'] as const).map(template =>
        visualizer({
            template,
            title: `gl-js-${template}`,
            filename: `staging/${template}.html`,
            gzipSize: true,
            brotliSize: true,
            sourcemap: true,
            open: true
        }) as unknown as Plugin
    ) : [])
];
